const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x120f18);this.p=this.add.circle(W/2,H-60,10,0x86efac);this.physics.add.existing(this.p);this.b=this.add.circle(W/2,90,18,0xf87171);this.t=this.add.text(10,10,'Survive: 30');this.sec=30;this.proj=this.physics.add.group();this.c=this.input.keyboard.createCursorKeys();this.r=this.input.keyboard.addKey('R');this.time.addEvent({delay:300,loop:true,callback:()=>{const o=this.add.circle(this.b.x,this.b.y,5,0xfde68a);this.physics.add.existing(o);const a=Phaser.Math.FloatBetween(0,Math.PI*2);o.body.setVelocity(Math.cos(a)*180,Math.sin(a)*180);this.proj.add(o);}});this.physics.add.overlap(this.p,this.proj,()=>this.end('HIT'));this.time.addEvent({delay:1000,loop:true,callback:()=>{if(this.over)return;this.sec--;this.t.setText('Survive: '+this.sec);if(this.sec<=0)this.end('CLEAR');}});}end(m){if(this.over)return;this.over=true;this.add.text(W/2,H/2,m+'\nR',{align:'center'}).setOrigin(.5);}update(){if(this.r.isDown)this.scene.restart();if(this.over)return;const b=this.p.body;b.setVelocity(0);if(this.c.left.isDown)b.setVelocityX(-180);else if(this.c.right.isDown)b.setVelocityX(180);if(this.c.up.isDown)b.setVelocityY(-180);else if(this.c.down.isDown)b.setVelocityY(180);this.proj.getChildren().forEach(o=>{if(o.x<0||o.x>W||o.y<0||o.y>H)o.destroy();});}}new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,physics:{default:'arcade'},scene:[S]});
